%[text] # Comparison All
%[text] Direct comparison of static data for an arbitrary amount of cases.
clear; clc; close all hidden;
%%
%[text] ## Configuration
AXIS = 3; %[control:dropdown:7ac0]{"position":[8,9]}
BASE_FOLDER = "/Users/alexwang/Documents/MATLAB/Linear Traverse/Data"; %[control:filebrowser:1a7f]{"position":[15,70]}
OUT_FOLDER = "/Users/alexwang/Downloads"; %[control:filebrowser:2fa5]{"position":[14,41]}
DRONE = "Lower "; %[control:dropdown:7ade]{"position":[9,17]}
MAX = 1; %[control:slider:32c3]{"position":[7,8]}
ERRORBAR = true; %[control:checkbox:3bbe]{"position":[12,16]}
CF_VOLTAGE = 4;
%%
FOLDERS = {
    '2025_08_15_Y0_STAT', ...
    '2025_08_15_Y15_STAT', ...
    '2025_08_15_Y30_STAT', ...
    '2025_08_15_Y45_STAT' ...
};

LABELS = containers.Map(FOLDERS, { ...
    'ψ = 0°', ...
    'ψ = 15°', ...
    'ψ = 30°', ...
    'ψ = 45°' ...
});

% FOLDERS = {
%     '2025_08_15_Y90_STAT', ...
%     '2025_08_15_Y75_STAT', ...
%     '2025_08_15_Y60_STAT', ...
%     '2025_08_15_Y45_STAT' ...
% };
% 
% LABELS = containers.Map(FOLDERS, { ...
%     'ψ = 90°', ...
%     'ψ = 75°', ...
%     'ψ = 60°', ...
%     'ψ = 45°' ...
% });

% FOLDERS = {
%     '2025_08_15_Y0_STAT', ...
%     '2025_08_15_Y45_STAT' ...
%     '2025_08_15_Y90_STAT', ...
%     '2025_08_15_Y135_STAT', ...
%     '2025_08_15_Y180_STAT', ...
% };
% 
% LABELS = containers.Map(FOLDERS, { ...
%     'ψ = 0°', ...
%     'ψ = 45°' ...
%     'ψ = 90°', ...
%     'ψ = 135°', ...
%     'ψ = 180°', ...
% });

colors = slanCM('GnBu', 2 + length(FOLDERS)); %[output:704af998]
%%
name = DRONE + Config.NAMES(AXIS);
colors = colors(3:end, :);

out_folder = fullfile(OUT_FOLDER, strjoin(["comparison", "stacked", name], "-"));

if ~exist(out_folder, "dir")
    mkdir(out_folder);
end
%%
%[text] ## FT Comparison
%[text] Plot chosen axis versus distance. FT data pre-processing should account for orientation.
if AXIS <= 3
    DENOMINATOR = Config.W * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Force, $\bar{" + name + "}/W$"); %[output:0ca06341]
else
    DENOMINATOR = Config.W * Config.L * MAX;
    Process.format_plot("", "Separation, $\Delta z/l$", "Moment, $\bar{" + name + "}/(Wl)$");
end
%[output:0ca06341]
set(gcf, 'Position', [100 100 750 750]); %[output:0ca06341]
handles = gobjects(length(FOLDERS), 1);

for k = 1:length(FOLDERS)
    folder = FOLDERS{k};
    load(fullfile(BASE_FOLDER, folder, 'processed_data.mat'), 'results');
    SDS = results.(name).SD / (Config.L / 1000);
    static = table2array(results.(name)(:, 2:end)) / DENOMINATOR;

    if ERRORBAR == true
        % Plot results (error bars)
        h = errorbar(SDS, mean(static, 2), std(static, 0, 2), 'o--', 'Color', colors(k, :), 'MarkerFaceColor', colors(k, :), 'LineWidth', 1.5); %[output:0ca06341]
    else
        % Plot results (data)
        h = plot(SDS, static, "x", 'Color', colors(k, :), "MarkerSize", 8, "LineWidth", 1.5);
    end

    handles(k) = h(1);
end

legend(handles, values(LABELS, FOLDERS), 'Location', 'northeast'); %[output:0ca06341]

%% Save
exportgraphics(gca, fullfile(out_folder, "FT.svg"), 'ContentType', 'vector'); %[output:0ca06341]
exportgraphics(gca, fullfile(out_folder, "FT.png")); %[output:0ca06341]
savefig(gcf, fullfile(out_folder, "FT.fig"));
%%
%[text] ## Crazyflie Power
figure; %[output:8a62d2ef]
Process.format_plot("", "Separation, $\Delta z/l$", "Power, W"); %[output:8a62d2ef]
%[output:8a62d2ef]
set(gcf, 'Position', [100 100 750 750]); %[output:8a62d2ef]
handles = gobjects(length(FOLDERS), 1);

for k = 1:length(FOLDERS)
    folder = FOLDERS{k};
    load(fullfile(BASE_FOLDER, folder, 'processed_data.mat'), 'results');
    SDS = results.(name).SD / (Config.L / 1000);
    current = table2array(results.(DRONE + "Current")(:, 2:end));
    voltage = table2array(results.(DRONE + "Voltage")(:, 2:end));
    power = current .* voltage;

    if ERRORBAR == true
        % Plot results (error bars)
        h = errorbar(SDS, mean(power, 2), std(power, 0, 2), 'o--', 'Color', colors(k, :), 'MarkerFaceColor', colors(k, :), 'LineWidth', 1.5); %[output:8a62d2ef]
    else
        % Plot results (data)
        h = plot(SDS, power, "x", 'Color', colors(k, :), "MarkerSize", 8, "LineWidth", 1.5);
    end

    handles(k) = h(1);
end

legend(handles, values(LABELS, FOLDERS), 'Location', 'northeast'); %[output:8a62d2ef]

%% Save
exportgraphics(gca, fullfile(out_folder, "power.svg"), 'ContentType', 'vector'); %[output:8a62d2ef]
exportgraphics(gca, fullfile(out_folder, "power.png")); %[output:8a62d2ef]
savefig(gcf, fullfile(out_folder, "power.fig"));
%%
%[text] ## Crazyflie Voltage
figure; %[output:54be919c]
Process.format_plot("", "Separation, $\Delta z/l$", "Voltage, V");

set(gcf, 'Position', [100 100 750 750]);
handles = gobjects(length(FOLDERS), 1);

for k = 1:length(FOLDERS)
    folder = FOLDERS{k};
    load(fullfile(BASE_FOLDER, folder, 'processed_data.mat'), 'results');
    SDS = results.(name).SD / (Config.L / 1000);
    voltage = table2array(results.(DRONE + "Voltage")(:, 2:end));

    if ERRORBAR == true
        % Plot results (error bars)
        h = errorbar(SDS, mean(voltage, 2), std(voltage, 0, 2), 'o--', 'Color', colors(k, :), 'MarkerFaceColor', colors(k, :), 'LineWidth', 1.5);
    else
        % Plot results (data)
        h = plot(SDS, voltage, "x", 'Color', colors(k, :), "MarkerSize", 8, "LineWidth", 1.5);
    end

    handles(k) = h(1);
end

legend(handles, values(LABELS, FOLDERS), 'Location', 'northeast');

%% Save
exportgraphics(gca, fullfile(out_folder, "voltage.svg"), 'ContentType', 'vector');
exportgraphics(gca, fullfile(out_folder, "voltage.png"));
savefig(gcf, fullfile(out_folder, "voltage.fig"));
%%
%[text] ## Peak Frequencies
figure %[output:00141bb4]
Process.format_plot("", "Separation, $\Delta z/l$", "Propeller Speed, Hz"); %[output:00141bb4]
%[output:00141bb4]
set(gcf, 'Position', [100 100 750 750]); %[output:00141bb4]
handles = gobjects(length(FOLDERS), 1);

for k = 1:length(FOLDERS)
    folder = FOLDERS{k};
    load(fullfile(BASE_FOLDER, folder, 'processed_data.mat'), 'results');
    SDS = results.(name).SD / (Config.L / 1000);
    rps = table2array(results.(DRONE + "RPS")(:, 2:end));

    plot(SDS, median(rps, 2), ".-", 'Color', colors(k, :), 'LineWidth', 1.5, 'MarkerSize', 15); %[output:00141bb4]
end

legend(values(LABELS, FOLDERS), 'Location', 'northeast'); %[output:00141bb4]

%% Save
exportgraphics(gca, fullfile(out_folder, "frequency.svg"), 'ContentType', 'vector'); %[output:00141bb4]
exportgraphics(gca, fullfile(out_folder, "frequency.png")); %[output:00141bb4]
savefig(gcf, fullfile(out_folder, "frequency.fig"));

